// Read structured form output вЂ” handles both form field names and pre-processed JSON keys
const f = $json;

const role      = String(f['Job Role']              || f['role']            || '').trim() || 'Software Developer';
const location  = String(f['Location']              || f['location']        || '').trim() || 'India';
const remoteRaw = String(f['Remote Work?']          || f['isRemote']        || '').toLowerCase();
const jtRaw     = String(f['Job Type']              || f['jobType']         || '').toLowerCase();
const elRaw     = String(f['Experience Level']      || f['experienceLevel'] || '').toLowerCase();
const chatId    = String(f['Your Telegram Chat ID'] || f['telegramChatId']  || '').trim();

const isRemote = remoteRaw.includes('yes') || remoteRaw === 'true';

const jtParam =
  jtRaw.includes('contract') || jtRaw.includes('freelance') ? '&f_JT=C' :
  jtRaw.includes('intern')   ? '&f_JT=I' :
  jtRaw.includes('part')     ? '&f_JT=P' : '&f_JT=F';

const remoteParam = isRemote ? '&f_WT=2' : '';

const expParam =
  elRaw.includes('entry') || elRaw.includes('fresher') ? '&f_E=1,2' :
  elRaw.includes('senior') || elRaw.includes('lead')   ? '&f_E=4,5' : '&f_E=3,4';

const searchUrl =
  'https://www.linkedin.com/jobs/search/?keywords=' + encodeURIComponent(role) +
  '&location=' + encodeURIComponent(location) +
  remoteParam + jtParam + expParam +
  '&f_TPR=r604800&position=1&pageNum=0';

return [{
  json: {
    role,
    location,
    isRemote,
    jobType:         jtRaw,
    experienceLevel: elRaw,
    searchUrl,
    telegramChatId:  chatId
  }
}];

// в”Ђв”Ђв”Ђ Safe string helper в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
const str = (v) => {
  if (v === null || v === undefined || v === false || v === true) return '';
  const s = String(v).trim();
  return (s === 'null' || s === 'undefined' || s === 'false' || s === 'N/A') ? '' : s;
};

// в”Ђв”Ђв”Ђ Inputs в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
// Direct predecessor is Get Resume (Google Docs)
const resumeRaw = str($input.first().json.content);
const resumeSnippet = resumeRaw.replace(/\s+/g, ' ').trim().substring(0, 800);

// All scraped jobs from Apify
const apifyItems  = $('Apify: Scrape LinkedIn Jobs').all();

// All existing sheet rows (for duplicate check)
const sheetRows   = $('Read: Existing Sheet Rows').all();

// Build a set of companies already in the sheet (Sent OR Pending) вЂ” lowercase
const existingCompanies = new Set(
  sheetRows
    .map(r => str(r.json['Company']).toLowerCase())
    .filter(c => c.length > 0)
);

// Search context
const searchCtx = $('Build LinkedIn Search URL').first().json;
const searchRole   = str(searchCtx.role);
const telegramChatId = str(searchCtx.telegramChatId);

// в”Ђв”Ђв”Ђ Process each scraped job в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
const newJobs = [];
const seenCompanies = new Set(); // dedup within this run

for (const item of apifyItems) {
  const d = item.json;

  // в”Ђв”Ђ Company name вЂ” try every possible Apify field name в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
  const company = str(d.companyName) || str(d.company) || str(d.employer) || str(d.organizationName) || '';
  if (!company) continue; // skip jobs with no company

  const companyLower = company.toLowerCase();
  if (existingCompanies.has(companyLower)) continue; // already in sheet
  if (seenCompanies.has(companyLower)) continue;     // dup within this run
  seenCompanies.add(companyLower);

  // в”Ђв”Ђ Job title в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
  const jobTitle = str(d.title) || str(d.jobTitle) || str(d.position) || str(d.name) || searchRole || 'Developer';

  // в”Ђв”Ђ Location в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
  const location = str(d.location) || str(d.jobLocation) || str(d.city) || '';

  // в”Ђв”Ђ Company website / domain в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
  const website = str(d.companyWebsite) || str(d.companyUrl) || str(d.company_url) || '';
  const domain  = website
    .replace(/https?:\/\/(www\.)?/, '')
    .split('/')[0].split('?')[0].trim();

  // в”Ђв”Ђ Job URL в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
  const jobUrl = str(d.link) || str(d.jobUrl) || str(d.url) || str(d.applyUrl) || str(d.externalApplyLink) || '';

  // в”Ђв”Ђ Salary в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
  const salary = str(d.salary) || str(d.salaryRange) || str(d.compensation) || '';

  // в”Ђв”Ђ Applicants в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
  const applicants = str(d.applicantsCount) || str(d.numberOfApplicants) || str(d.applicants) || '';

  // в”Ђв”Ђ Employment type в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
  const jobType = str(d.employmentType) || str(d.jobType) || str(d.workType) || '';

  // в”Ђв”Ђ Posted date в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
  const postedDate = str(d.postedDate) || str(d.postedAt) || str(d.datePosted) || str(d.listedAt) || '';

  // в”Ђв”Ђ Description вЂ” clean HTML entities and tags, cap at 600 for sheet в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
  const rawDesc = str(d.descriptionText) || str(d.description) || str(d.jobDescription) || '';
  const descClean = rawDesc
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"').replace(/&#39;/g, "'")
    .replace(/&[a-z]+;/gi, ' ')
    .replace(/\s+/g, ' ').trim();

  const descForSheet = descClean.substring(0, 600);
  const descForEmail = descClean.substring(0, 1500); // richer for AI email

  newJobs.push({
    json: {
      // в”Ђв”Ђ Columns to save in Sheet в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
      Timestamp:           new Date().toISOString(),
      Company:             company,
      'Job Title':         jobTitle,
      Location:            location,
      Salary:              salary,
      Applicants:          applicants,
      'Job Type':          jobType,
      'Posted Date':       postedDate,
      'Job URL':           jobUrl,
      'Company Website':   website,
      'Company Domain':    domain,
      'Job Description':   descForSheet,
      'Resume Snippet':    resumeSnippet,
      'Send Status':       'Pending',
      'Recruiter Email':   '',
      'Email Sent Date':   '',
      // в”Ђв”Ђ Pass-through (used in loop, not saved in sheet) в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
      _descForEmail:       descForEmail,
      _resumeSnippet:      resumeSnippet,
      _telegramChatId:     telegramChatId
    }
  });
}

if (newJobs.length === 0) {
  return [{
    json: {
      _skip: true,
      _telegramChatId: telegramChatId,
      _message: 'No new companies found. All scraped companies are already in the sheet.'
    }
  }];
}

return newJobs;

// After saving all Pending rows, carry forward the telegramChatId and total count
// We can't get it directly from the sheet save output вЂ” pull from the Prepare node
const preparedItems = $('Prepare + Deduplicate Jobs').all();
const totalFound = preparedItems.filter(i => !i.json._skip).length;
const telegramChatId = (preparedItems[0]?.json?._telegramChatId || '').trim();

return [{ json: { totalFound, telegramChatId } }];

// Calculate success rate and build summary message
const rows = $input.all();
const total   = rows.length;
const sent    = rows.filter(r => String(r.json['Send Status'] || '').toLowerCase() === 'sent').length;
const failed  = rows.filter(r => String(r.json['Send Status'] || '').toLowerCase().startsWith('failed')).length;
const skipped = rows.filter(r => String(r.json['Send Status'] || '').toLowerCase().includes('skipped')).length;
const pending = rows.filter(r => String(r.json['Send Status'] || '').toLowerCase() === 'pending').length;

const successRate = total > 0 ? Math.round((sent / total) * 100) : 0;

// List sent companies
const sentList = rows
  .filter(r => String(r.json['Send Status'] || '').toLowerCase() === 'sent')
  .slice(0, 10)
  .map(r => '  вЂў ' + String(r.json['Company'] || '') + ' вЂ” ' + String(r.json['Recruiter Email'] || 'email sent'))
  .join('\n');

const sheetUrl = 'https://docs.google.com/spreadsheets/d/REPLACE_WITH_YOUR_GOOGLE_SHEET_ID';

const message =
  'Job Hunt Complete!\n\n' +
  'Results:\n' +
  '  Emails Sent:    ' + sent + '\n' +
  '  Failed:         ' + failed + '\n' +
  '  Skipped:        ' + skipped + '\n' +
  '  Success Rate:   ' + successRate + '%\n' +
  '  Total in Sheet: ' + total + '\n\n' +
  (sentList ? 'Companies Emailed:\n' + sentList + '\n\n' : '') +
  'View full sheet:\n' + sheetUrl;

// Pull telegramChatId from context node
const ctx = $('Capture Run Context').first().json;
const telegramChatId = String(ctx.telegramChatId || '');

return [{ json: { message, telegramChatId } }];

