const str = (v) => {
  if (v === null || v === undefined || v === false) return '';
  return String(v).trim();
};

// в”Ђв”Ђ Strips forbidden/clichГ© phrases from email body в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
const sanitizeBody = (text) => {
  const banned = [
    /I am eager to contribute[^.]*\./gi,
    /I would love the opportunity[^.]*\./gi,
    /Please find (my resume|it|them) attached[^.]*\./gi,
    /I am writing to express my interest[^.]*\./gi,
    /I came across your job posting[^.]*\./gi,
    /My resume,\s*detailing[^.]*\./gi,
  ];
  let clean = text;
  for (const pattern of banned) clean = clean.replace(pattern, '').trim();
  // Collapse accidental double blank lines left behind
  clean = clean.replace(/\n{3,}/g, '\n\n');
  return clean.trim();
};

const items = $input.all();
return items.map(item => {
  const d = item.json;
  const sheetData = $('Loop: One Job at a Time').item.json;

  const company  = str(sheetData['Company']);
  const jobTitle = str(sheetData['Job Title']);
  const jobUrl   = str(sheetData['Job URL']);
  const location = str(sheetData['Location']);
  const salary   = str(sheetData['Salary']);
  const domain   = str(sheetData['Company Domain']);

  // в”Ђв”Ђ Parse AI JSON output в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
  let raw = str(d.output) || str(d.text) || '';
  raw = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  let ai = {};
  const fi = raw.indexOf('{');
  const li = raw.lastIndexOf('}');
  if (fi !== -1 && li !== -1) {
    try { ai = JSON.parse(raw.substring(fi, li + 1)); } catch(e) {}
  }

  // Regex fallback for cut-off / broken JSON
  const extractField = (fieldName) => {
    const regex = new RegExp('"' + fieldName + '"\\s*:\\s*"((?:[^"\\\\]|\\\\.)*)"');
    const match = raw.match(regex);
    return match ? match[1].replace(/\\n/g, '\n').replace(/\\"/g, '"').trim() : '';
  };

  const hrEmail    = str(ai.hr_email)         || extractField('hr_email');
  const subject    = str(ai.email_subject)    || extractField('email_subject');
  let   bodyPlain  = str(ai.email_body)       || extractField('email_body');
  const confidence = str(ai.email_confidence) || extractField('email_confidence') || 'medium';

  // в”Ђв”Ђ Fallback email address в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
  const finalEmail = hrEmail || (domain ? 'careers@' + domain : '');
  if (!finalEmail) {
    return {
      json: {
        _error: true,
        _errorMsg: 'No hr_email and no domain to guess from',
        company, job_title: jobTitle, job_url: jobUrl
      }
    };
  }

  // в”Ђв”Ђ Fallback body if AI returned nothing в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
  if (!bodyPlain) {
    bodyPlain =
      `Your work on ${jobTitle}-related challenges at ${company} caught my attention вЂ” ` +
      `especially the focus on building products that actually hold up at scale.\n\n` +
      `My background covers the core requirements for this role, and I'm confident I can ` +
      `deliver quality results from day one. My resume is attached.\n\n` +
      `Would love to find 15 minutes to connect.\n\nBest regards,\nSmit Chavda`;
  }

  // в”Ђв”Ђ Sanitize body (remove any surviving forbidden phrases) в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
  bodyPlain = sanitizeBody(bodyPlain);

  // в”Ђв”Ђ Convert plain-text в†’ clean HTML в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
  const paras = bodyPlain
    .split(/\n{2,}/)
    .map(p => p.replace(/\n/g, ' ').trim())
    .filter(p => p.length > 0);

  const htmlBody =
    '<div style="font-family:Arial,Helvetica,sans-serif;font-size:14px;line-height:1.7;color:#1a1a1a;max-width:580px;">'
    + paras.map(p => '<p style="margin:0 0 18px 0;">' + p + '</p>').join('')
    + '</div>';

  return {
    json: {
      to_email:         finalEmail,
      email_subject:    subject || ('Application for ' + jobTitle + ' вЂ“ Smit Chavda'),
      email_html:       htmlBody,
      email_confidence: confidence,
